const u=n=>{if(!n)return"Unknown error occurred";if(typeof n=="string")return n.includes("user rejected")||n.includes("User denied")?"User rejected the transaction":n;const e=n.message||"",r=n.code,i=n.reason,c=n.shortMessage||"",s=`${e} ${c} ${i||""}`.toLowerCase(),a={notregistered:"账户未注册，无法执行该操作",protocolpausederror:"协议已暂停，请稍后再试",zeroamount:"金额为 0，暂无可操作余额",insufficientbalance:"余额不足，无法提现",miningpooldepleted:"矿池余额不足，请联系管理员",checkintooearly:"签到间隔未到，请稍后再试"};for(const[t,o]of Object.entries(a))if(s.includes(t))return o;if(e.includes("user rejected")||e.includes("User denied")||r==="ACTION_REJECTED"||r===4001)return"Transaction cancelled by user";if(e.includes("insufficient funds")||e.includes("exceeds balance")||r==="INSUFFICIENT_FUNDS")return"Insufficient funds for transaction";if(i)return`Transaction failed: ${i}`;if(e.includes("execution reverted")){const t=e.match(/execution reverted:? (.*?)(?:\"|$)/);return t&&t[1]?`Transaction failed: ${t[1]}`:s.includes("require(false)")||s.includes('data: "0x"')||s.includes("data: 0x")?"合约执行失败（无详细回滚信息），常见原因：协议余额不足/地址配置错误/网络不匹配":"Transaction failed: Execution reverted"}if(e.includes("missing revert data")||r==="CALL_EXCEPTION")return n.data&&n.data!=="0x"?"Transaction failed: Contract execution error":"合约调用失败且无回滚数据，请检查网络、合约地址和协议资金池余额";if(e.includes("Internal JSON-RPC error")){const t=e.match(/message":"(.*?)"/);return t&&t[1]?`RPC Error: ${t[1]}`:"Internal Wallet/RPC Error"}return e.includes("Network Error")||r==="NETWORK_ERROR"?"Network connection error. Please check your internet or RPC URL.":e&&e.length<80&&!e.includes("{")?e:"Transaction failed. Please check details in console."};export{u as f};
